// ConnectivityConfig defines model for ConnectivityConfig.
type ConnectivityConfig struct {
	// CriticalSec Probe interval for unreachable hosts below the threshold (60..86400). Default 120 (2m)
	CriticalSec int `json:"critical_sec"`

	// DegradedSec Probe interval for reachable hosts with consecutive_failures>=1 (60..86400). Default 300 (5m)
	DegradedSec int `json:"degraded_sec"`

	// DownSec Probe interval for hosts at or above the threshold (60..86400). Default 1800 (30m)
	DownSec int `json:"down_sec"`

	// MaintenanceGlobal When true, probe loop ticks but probes no hosts
	MaintenanceGlobal bool `json:"maintenance_global"`

	// MaintenanceSec Persisted band interval for hosts in maintenance (60..86400). Default 3600 (60m). Not yet auto-applied; tracked for the per-host maintenance slice
	MaintenanceSec int `json:"maintenance_sec"`

	// OnlineSec Probe interval for reachable hosts with consecutive_failures=0 (60..86400). Default 900 (15m)
	OnlineSec int `json:"online_sec"`

	// RateLimit Max concurrent SSH connections during fleet sweeps (1..200)
	RateLimit int `json:"rate_limit"`

	// TimeoutSec Per-probe TCP-banner timeout in seconds (1..30)
	TimeoutSec int `json:"timeout_sec"`

	// UnreachableThreshold Consecutive failures before reachable→unreachable (1..10)
	UnreachableThreshold int `json:"unreachable_threshold"`
}

